```class Solution {
public:
    vector<int> validSequence(string word1, string word2) {
        int m = word1.size(), n = word2.size();
        vector<int> res;
        int diff = 0;
        for (int i = 0, j = 0; i < m && j < n; ++i) {
            if (word1[i] != word2[j]) {
                ++diff;
                if (diff > 1) break;
                res.push_back(i);
            } else {
                ++j;
            }
        }
        if (diff > 1 || j < n) return {};
        return res;
    }
};
